import { isValidLadderName } from './task04';

describe('isValidLadderName', () => {
  it('accepts valid names', () => {
    expect(isValidLadderName('Main Ladder')).toBe(true);
    expect(isValidLadderName('test_name')).toBe(true);
    expect(isValidLadderName('a')).toBe(true);
  });

  it('rejects invalid names', () => {
    expect(isValidLadderName('')).toBe(false);
    expect(isValidLadderName('   ')).toBe(false);
    expect(isValidLadderName('a'.repeat(21))).toBe(false);
    expect(isValidLadderName('name!')).toBe(false);
  });
});
